import i18n from 'i18next';
import { initReactI18next } from 'react-i18next';
import LanguageDetector from 'i18next-browser-languagedetector';

// 导入翻译文件
import enTranslation from './locales/en.json';
import zhTranslation from './locales/zh.json';

// 添加额外的调试日志
const originalT = i18n.t;
i18n.t = function(key, options) {
  const value = originalT.call(this, key, options);
  
  // 检查是否返回了键名本身，这通常意味着未找到翻译
  if (value === key && process.env.NODE_ENV === 'development') {
    console.warn(`[i18n] Missing translation key: ${key}, current language: ${i18n.language}`);
  }
  
  return value;
};

i18n
  // 检测用户语言
  .use(LanguageDetector)
  // 将i18n实例传递给react-i18next
  .use(initReactI18next)
  // 初始化i18next
  .init({
    debug: process.env.NODE_ENV === 'development',
    fallbackLng: 'zh',
    interpolation: {
      escapeValue: false, // 不转义
    },
    resources: {
      en: {
        translation: enTranslation,
      },
      zh: {
        translation: zhTranslation,
      },
    },
  });

export default i18n;
